class Solution {
public:
    string concatHex36(int n) {
        int n2 = n * n;
        string hex;
        while (n2 > 0) {
            int rem = n2 % 16;
            hex = "0123456789ABCDEF"[rem] + hex;
            n2 = n2 / 16;
        }
        int n3 = n * n * n;
        string base36;
        while (n3 > 0) {
            int rem = n3 % 36;
            base36 = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"[rem] + base36;
            n3 = n3 / 36;
        }
        return hex + base36;
    }
};

